var text = msg.payload.content;
var chatId = msg.payload.chatId;

if (text.startsWith("/limit ")) {
    var casti = text.split(" ");

    if (casti.length < 4) {
        return [null, { payload: { chatId: chatId, type: 'message', content: "❌ Nesprávny formát!\nPošli /pomoc pre zobrazenie nápovedy." } }, null];
    }

    var zariadenie = casti[1].toLowerCase();
    var velicina = casti[2].toLowerCase(); 

    var rozsahoveVeliciny = ["teplota", "vlhkost", "prach", "voc"];
    var jednociselneVeliciny = ["tmin", "tmax", "hmin", "hmax", "pmax"];
    var povoleneVeliciny = rozsahoveVeliciny.concat(jednociselneVeliciny);

    if (!povoleneVeliciny.includes(velicina)) {
        return [null, { payload: { chatId: chatId, type: 'message', content: "❌ Neznáma veličina!\nPošli /pomoc pre zoznam veličín." } }, null];
    }

    // ─── NOVÁ POISTKA: Zakázať jednocíselné veličiny pre RPi ───
    if (zariadenie === "rpi" && jednociselneVeliciny.includes(velicina)) {
        return [null, { payload: { chatId: chatId, type: 'message', content: "❌ Tieto hardvérové limity (tmin, tmax...) fungujú iba pre Wio Terminal!\nPre RPi použi rozmedzie, napr.: /limit rpi teplota 20 28" } }, null];
    }
    // ───────────────────────────────────────────────────────────

    var hodnoty = "";
    var apiVelicina = velicina; 

    if (rozsahoveVeliciny.includes(velicina)) {
        if (casti.length !== 5) {
            return [null, { payload: { chatId: chatId, type: 'message', content: "❌ " + velicina.toUpperCase() + " vyžaduje rozsah dvoch čísel (MIN a MAX).\nPríklad: /limit " + zariadenie + " " + velicina + " 20 28" } }, null];
        }
        var hodnota1 = parseFloat(casti[3]);
        var hodnota2 = parseFloat(casti[4]);

        if (isNaN(hodnota1) || isNaN(hodnota2)) {
            return [null, { payload: { chatId: chatId, type: 'message', content: "❌ Limity musia byť čísla!" } }, null];
        }

        if (hodnota1 > hodnota2) {
            hodnoty = hodnota2 + " " + hodnota1;
        } else {
            hodnoty = hodnota1 + " " + hodnota2;
        }
    } 
    else if (jednociselneVeliciny.includes(velicina)) {
        if (casti.length !== 4) {
            return [null, { payload: { chatId: chatId, type: 'message', content: "❌ Pre " + velicina.toUpperCase() + " zadaj iba jedno číslo.\nPríklad: /limit " + zariadenie + " " + velicina + " 15" } }, null];
        }
        var hodnota = parseFloat(casti[3]);
        if (isNaN(hodnota)) {
            return [null, { payload: { chatId: chatId, type: 'message', content: "❌ Hodnota musí byť číslo!" } }, null];
        }
        hodnoty = hodnota.toString();
    }

    if (velicina === "tmin") velicina = "tMin";
    if (velicina === "tmax") velicina = "tMax";
    if (velicina === "hmin") velicina = "hMin";
    if (velicina === "hmax") velicina = "hMax";
    if (velicina === "pmax") velicina = "pMax";

    flow.set(zariadenie + "_limit_" + apiVelicina, hodnoty);

    var mqttTopic = "uzol/" + zariadenie + "/limit/" + velicina;
    var msgPreMQTT = { topic: mqttTopic, payload: hodnoty };
    var msgPreTelegram = {
        payload: {
            chatId: chatId,
            type: 'message',
            content: "✅ Limity spracované pre " + zariadenie.toUpperCase() + "\nNastavené: " + hodnoty.replace(" ", " až ")
        }
    };

    var webHodnota = hodnoty.replace(" ", " - "); 
    var msgPreAPI = {
        payload: { "key": zariadenie + "_" + apiVelicina, "value": webHodnota }
    };

    return [msgPreMQTT, msgPreTelegram, msgPreAPI];
}

