var tema = msg.topic; // napr. "uzol/wio/upozornenie"

// ── EXTRAKCIA ZARIADENIA Z MQTT TÉMY ──
var castiTemy = tema.split('/');
var zariadenie = "NEZNÁME";

if (castiTemy.length >= 2) {
