var casti = msg.topic.split('/');
if (casti.length !== 3) return null;

var zariadenie = casti[1];
var velicina = casti[2];
var hodnota = parseFloat(msg.payload);

if (isNaN(hodnota)) return null;

// ─── 1. ULOŽENIE DO PAMÄTE (Pre API a príkazy /stav) ───
flow.set(zariadenie + '_' + velicina, hodnota);

// ─── 2. KONTROLA LIMITOV IBA PRE RPi ───
// (Wio Terminal si to kontroluje sám a posiela hotové upozornenia)
if (zariadenie === 'rpi') {
    var predvoleneLimity = {
        "teplota": "20 28",
        "vlhkost": "40 60",
        "voc": "0 500"
    };

    // Vezmeme limit z Telegramu, alebo použijeme predvolený
    var limityText = flow.get("rpi_limit_" + velicina) || predvoleneLimity[velicina];

    if (limityText) {
        var limityCasti = limityText.split(" ");
        if (limityCasti.length === 2) {
            var minLimit = parseFloat(limityCasti[0]);
            var maxLimit = parseFloat(limityCasti[1]);

            // Spam-poistka (aby ti nechodilo 100 správ za minútu)
            var stavUpozorneniaKey = "rpi_alert_" + velicina;
            var uzJeUpozornene = flow.get(stavUpozorneniaKey) || false;
            var textSpravy = null;

            if (hodnota > maxLimit) {
                if (!uzJeUpozornene) { // Poslať poplach, len ak sme ho ešte neposlali
                    textSpravy = "🚨 UPOZORNENIE!\nRPi prekročilo maximálny limit pre " + velicina.toUpperCase() + "!\nAktuálna hodnota: " + hodnota + " (Max: " + maxLimit + ")";
                    flow.set(stavUpozorneniaKey, true);
                }
            } else if (hodnota < minLimit) {
                if (!uzJeUpozornene) {
                    textSpravy = "🚨 UPOZORNENIE!\nRPi kleslo pod minimálny limit pre " + velicina.toUpperCase() + "!\nAktuálna hodnota: " + hodnota + " (Min: " + minLimit + ")";
                    flow.set(stavUpozorneniaKey, true);
                }
            } else {
                // Hodnota sa vrátila do normálu medzi MIN a MAX
                if (uzJeUpozornene) {
                    textSpravy = "✅ HODNOTA V NORME\nRPi (" + velicina.toUpperCase() + ") sa vrátilo do normálu.\nAktuálna hodnota: " + hodnota;
                    flow.set(stavUpozorneniaKey, false); // Odblokujeme poistku
                }
            }

            // Ak máme vytvorenú správu, odošleme ju botovi
            if (textSpravy) {
                return {
                    payload: {
                        chatId: "YOUR_CHAT_ID_HERE", // Nahraď dané Chat ID z predchádzajúceho overenia
                        type: 'message',
                        content: textSpravy
                    }
                };
            }
        }
    }
}

