var text = msg.payload.content;
var chatId = msg.payload.chatId;

if (text.startsWith('/stav ')) {
    var zariadenie = text.split(' ')[1].toLowerCase(); 

    // ── KONTROLA EXISTENCIE ZARIADENIA ──
    var povoleneZariadenia = ['rpi', 'wio'];
    if (!povoleneZariadenia.includes(zariadenie)) {
        return {
            payload: {
                chatId: chatId,
                type: 'message',
                content: "❌ Neznáme zariadenie '" + zariadenie + "'!\nPošli /pomoc pre zoznam dostupných zariadení a príkazov."
            }
        };
    }
    // ────────────────────────────────────

    var t = parseFloat(flow.get(zariadenie + '_teplota'));
    var h = parseFloat(flow.get(zariadenie + '_vlhkost'));
    var p = flow.get(zariadenie + '_prach'); 
    var v = flow.get(zariadenie + '_voc');

    // ── MATEMATICKÝ MODEL KOMFORTU (Z grafu) ──
    function zistiKomfort(temp, hum) {
        if (isNaN(temp) || isNaN(hum)) return "Neznámy (chýbajú dáta)";

        // Súradnice [Teplota, Vlhkosť] odčítané z grafu
        var zameriavanie_komfort = [[19.0, 74.0], [23.5, 68.0], [25.8, 35.0], [20.0, 37.0]];
        var zameriavanie_moderate = [[18.2, 80.0], [24.5, 75.0], [27.2, 31.0], [25.8, 18.0], [21.5, 19.0], [18.5, 28.0], [16.8, 62.0]];

        // Algoritmus Point-in-Polygon (Ray Casting)
        function jeVoVnutri(point, polygon) {
            var x = point[0], y = point[1];
            var voVnutri = false;
            for (var i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
                var xi = polygon[i][0], yi = polygon[i][1];
                var xj = polygon[j][0], yj = polygon[j][1];
                var presek = ((yi > y) != (yj > y)) && (x < (xj - xi) * (y - yi) / (yj - yi) + xi);
                if (presek) voVnutri = !voVnutri;
            }
            return voVnutri;
        }

        // Vyhodnotenie zón
        if (jeVoVnutri([temp, hum], zameriavanie_komfort)) return "Komfortné";
        if (jeVoVnutri([temp, hum], zameriavanie_moderate)) return "Prijateľné";

        // Ak je bod mimo polygónov, určíme prečo je to nepríjemné
        if (hum > 75) return "Nepríjemné - Príliš vlhko";
        if (hum < 20) return "Nepríjemné - Príliš sucho";
        if (temp < 18) return "Nepríjemné - Chladno";
        return "Nepríjemné - Horúco";
    }

    // Vypočítame aktuálny komfort
    var stavKomfortu = zistiKomfort(t, h);

    // Ošetrenie textu pre zobrazenie (ak dáta ešte nedorazili)
    var t_str = isNaN(t) ? "? (čakám na dáta)" : t;
    var h_str = isNaN(h) ? "? (čakám na dáta)" : h;

    // Zostavenie odpovede pre Telegram
    var sprava = "📊 Aktuálny stav " + zariadenie.toUpperCase() + ":\n\n";
    sprava += "🌡️ Teplota: " + t_str + " °C\n";
    sprava += "💧 Vlhkosť: " + h_str + " %\n";
    sprava += "🛋️ Komfort: " + stavKomfortu + "\n\n";

    if (zariadenie === 'wio' && p) {
        sprava += "💨 Prach: " + p + " µg/m³";
    } else if (zariadenie === 'rpi' && v) {
        sprava += "💨 TVOC: " + v + " ppm";
    }

    return {
        payload: {
            chatId: chatId,
            type: 'message',
            content: sprava,
            parse_mode: 'HTML' 
        }
    };
}
